#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

uint32_t expand(uint32_t key) {
  key &= 0xFFFFF;
  return (key ^ (key << 16) ^ (key * 12345)) & 0xFFFFFFFF;
}

uint8_t g(uint8_t a, uint8_t b, uint8_t x) {
    uint8_t t=(a+b+x)&0xFF;
    return ((t<<2)|(t>>6))&0xFF;
}

uint32_t f(uint32_t inp) {
    uint8_t x[4]; uint32_t v=inp;
    for (int i=0;i<4;i++){ x[i]=v&0xFF; v>>=8; }
    uint8_t y[4];
    y[2]=g(x[3]^x[2], x[1]^x[0], 1);
    y[3]=g(x[3], y[2], 0);
    y[1]=g(x[1]^x[0], y[2], 0);
    y[0]=g(x[0], y[1], 1);
    uint32_t out=0;
    for (int i=0;i<4;i++) out|=((uint32_t)y[i])<<(8*i);
    return out;
}

int main(){
  // timing: brute all key3 for one pair, just compute one round reverse
  // pair0 hardcoded
  uint64_t P=367472469947502207ULL, C=14898973196205001976ULL;
  uint32_t L0=(P>>32)&0xFFFFFFFF, R0=(P&0xFFFFFFFF)^((P>>32)&0xFFFFFFFF);
  uint32_t R4=(C>>32)&0xFFFFFFFF, L4p=C&0xFFFFFFFF;
  uint32_t L4=L4p^R4;
  // After reverse post mix: left=L4, right=R4
  // Reverse round3: temp=left(L4), left=right(R4), mixed=f(temp^k3), right=temp, left^=mixed
  // So L3=R4^f(L4^k3), R3=L4
  volatile uint32_t acc=0;
  for (uint32_t k=0;k<(1<<20);k++){
    uint32_t K=expand(k);
    uint32_t L3=R4^f(L4^K);
    uint32_t R3=L4;
    acc^=L3^R3;
  }
  printf("done key3 loop acc=%08x\n", acc);
  return 0;
}
